import clsx from 'clsx';
import * as React from 'react';
import { UploadContextProvider } from './hooks/UploadContext';
import { useUpload } from './hooks/useUpload';
import type { ComposableUploadProps, UploadRef } from './interface';

export const ComposableUpload = React.forwardRef<UploadRef, React.PropsWithChildren<ComposableUploadProps>>(
  (props, ref) => {
    const { className, children, disabled, style, id } = props;

    const uploadCtxValue = useUpload(props, ref);
    const { rootPrefixCls } = uploadCtxValue;

    const classNames = clsx(
      {
        [rootPrefixCls]: true,
        [`${rootPrefixCls}--disabled`]: disabled,
      },
      className,
    );

    return (
      <UploadContextProvider value={uploadCtxValue}>
        <div className={classNames} style={style} id={id}>
          {children}
        </div>
      </UploadContextProvider>
    );
  },
);
